function actualizarTotalesCot() {
        let subtotal = 0, ivaTotal = 0;
        productosCotActual.forEach(p => {
          const base = (p.precioUnitario * p.cantidad) - (p.descuento || 0);
          subtotal += base;
        });
        if ((configNegocio.modoIVA || "producto") === "producto") {
          productosCotActual.forEach(p => {
            const base = (p.precioUnitario * p.cantidad) - (p.descuento || 0);
            ivaTotal += base * (p.iva / 100);
          });
        } else {
          ivaTotal = subtotal * ((configNegocio.ivaGeneral ?? 19) / 100);
        }
        const total = subtotal + ivaTotal;
        const elSub = $("cotSubtotal"), elIVA = $("cotIVA"), elTotal = $("cotTotal");
        if (elSub) elSub.innerText = money(subtotal);
        if (elIVA) elIVA.innerText = money(ivaTotal) + (configNegocio.modoIVA === "total" ? ` (${configNegocio.ivaGeneral ?? 19}% al total)` : "");
        if (elTotal) elTotal.innerText = money(total);
      }
