function registrarMovimientoStock(productoId, tipo, cantidad, motivo, refId) {
  const prod = catalogo.find(p => p.id === productoId);
  if (!prod) return false;
  const cant = Math.abs(Number(cantidad)) || 0;
  if (cant <= 0) return false;
  if (prod.stock === undefined || prod.stock === null) prod.stock = 0;
  if (tipo === "entrada") prod.stock = (prod.stock || 0) + cant;
  else if (tipo === "salida") prod.stock = Math.max(0, (prod.stock || 0) - cant);
  prod.actualizadoEn = new Date().toISOString();
  guardarCatalogoNegocio();
  return true;
}
