let dbPromise=null;
function initIndexedDB(){return new Promise((resolve,reject)=>{if(dbPromise){resolve(dbPromise);return}const req=indexedDB.open("BankingProOffline",3);req.onerror=()=>reject(req.error);req.onsuccess=()=>{dbPromise=req.result;resolve(dbPromise)};req.onupgradeneeded=(e)=>{const db=e.target.result;if(!db.objectStoreNames.contains("pendingQueue")){db.createObjectStore("pendingQueue",{keyPath:"id",autoIncrement:true});}if(!db.objectStoreNames.contains("config")){db.createObjectStore("config",{keyPath:"key"});}}});}
async function obtenerCola(){try{const db=await initIndexedDB();return new Promise((resolve,reject)=>{try{const tx=db.transaction("pendingQueue","readonly");const req=tx.objectStore("pendingQueue").getAll();req.onsuccess=()=>resolve(req.result||[]);req.onerror=()=>resolve([]);}catch(e){resolve([])}});}catch(e){return[];}}
async function eliminarDeCola(id){const db=await initIndexedDB();const tx=db.transaction("pendingQueue","readwrite");tx.objectStore("pendingQueue").delete(id);await new Promise((resolve,reject)=>{tx.oncomplete=resolve;tx.onerror=reject});await actualizarContadorPendientes();}
async function limpiarCola(){const db=await initIndexedDB();const tx=db.transaction("pendingQueue","readwrite");tx.objectStore("pendingQueue").clear();await new Promise((resolve,reject)=>{tx.oncomplete=resolve;tx.onerror=reject});await actualizarContadorPendientes();}
async function actualizarContadorPendientes(){const cola=await obtenerCola();const pc=$("pendingCount");if(pc)pc.innerText=cola.length;const sb=$("syncBadge");if(sb){if(cola.length>0){sb.innerText=`📤${cola.length}`;sb.style.background="rgba(245,158,11,.2)";sb.style.color="var(--warn)";}else{sb.innerText="✓";sb.style.background="rgba(34,197,94,.2)";sb.style.color="var(--ok)";}}return cola.length;}
function checkFB() {
    if (window.firebaseReady) {
      window.onUserChanged = onUserChanged;
      // Procesar usuario pendiente inmediatamente
      if (window._pendingUser !== undefined) {
        onUserChanged(window._pendingUser);
        window._pendingUser = undefined;
      } else {
        // Forzar verificación directa
        if (window.auth) {
          window.auth.onAuthStateChanged ?
            window.auth.onAuthStateChanged(u => onUserChanged(u)) :
            null;
        }
      }
    } else {
      setTimeout(checkFB, 100);
    }
  }
