function elegirCliente(id) {
    const c = clientes.find(x => x.id === id);
    if (!c) return;
    $("cotCliente").value = id;
    const sel = $("clienteSeleccionado");
    const nom = $("clienteSelNombre");
    if (sel) { sel.style.display = "flex"; }
    if (nom) nom.textContent = c.nombre + (c.empresa ? ' · ' + c.empresa : '');
    $("listaChipsClientes").style.display = "none";
    $("buscarClienteCot").value = "";
    toast("✅ " + c.nombre);
  }
function deseleccionarCliente() {
    $("cotCliente").value = "";
    const sel = $("clienteSeleccionado");
    if (sel) sel.style.display = "none";
    $("buscarClienteCot").value = "";
  }
