function enviarWhatsAppOrden(id) {
    const o = ordenes.find(x => x.id === id);
    if (!o) return;
    const est = ESTADOS_ORDEN[o.estado] || { label: o.estado };
    const emoji = { recibido: "📥", diagnostico: "🔍", en_reparacion: "🔧", listo: "✅", entregado: "📦" } [o.estado] || "📱";
    const negocio = configNegocio.razonSocial || "TECNOYORK";
    const tel = configNegocio.telefono || "";
    const mensajes = {
      recibido: `Hola ${o.clienteNombre} 👋\n\nTu equipo *${o.marca} ${o.modelo || ""}* fue recibido correctamente.\n\n📋 *Orden:* ${o.numero}\n🔧 *Reporte:* ${o.problema}\n\nTe avisamos cuando tengamos diagnóstico. ¡Gracias por confiar en ${negocio}! 🙏`,
      diagnostico: `Hola ${o.clienteNombre} 👋\n\nEstamos realizando el diagnóstico de tu *${o.marca} ${o.modelo || ""}*.\n\n📋 *Orden:* ${o.numero}\n💰 *Presupuesto estimado:* ${o.precioEstimado ? money(o.precioEstimado) : "pendiente"}\n\nTe confirmamos si procede la reparación. 🔍`,
      en_reparacion: `Hola ${o.clienteNombre} 🔧\n\nYa estamos reparando tu *${o.marca} ${o.modelo || ""}*.\n\n📋 *Orden:* ${o.numero}\n💰 *Valor:* ${o.precioEstimado ? money(o.precioEstimado) : "por confirmar"}\n\nTe avisamos cuando esté listo. ¡Pronto! ⚡`,
      listo: `Hola ${o.clienteNombre} ✅\n\n¡Tu equipo está LISTO para recoger!\n\n📱 *${o.marca} ${o.modelo || ""}*\n📋 *Orden:* ${o.numero}\n💰 *Total a pagar:* ${money(o.precioFinal || o.precioEstimado || 0)}\n\n📍 ${configNegocio.direccion || ""}\n📞 ${tel}\n\n¡Te esperamos! 🙌`,
      entregado: `Hola ${o.clienteNombre} 😊\n\nGracias por tu preferencia en *${negocio}*.\n\n✅ Tu *${o.marca} ${o.modelo || ""}* fue entregado.\n🛡️ Garantía: ${o.garantiaDias || 30} días.\n\nRecuerda que tenemos garantía. Si tienes algún problema, escríbenos. 💪`
    };
    const texto = mensajes[o.estado] || `Hola ${o.clienteNombre}, actualización de tu orden ${o.numero}: ${est.label}`;
    const numLimpio = (o.clienteTelefono || "").replace(/\D/g, "");
    const url = numLimpio ?
      `https://wa.me/57${numLimpio}?text=${encodeURIComponent(texto)}` :
      `https://wa.me/?text=${encodeURIComponent(texto)}`;
    window.open(url, "_blank");
  }
