function generarNotificacionesSiCorresponde(){
    const hoy=fechaHoyColombia();
    const key="ultimaGenNotif_"+contexto;
    if(localStorage.getItem(key)===hoy) return;
    generarNotificaciones();
    generarRecomendaciones();
    localStorage.setItem(key,hoy);
  }
function generarRecomendaciones(){
    const hoy=fechaHoyColombia();
    let ing=0,gas=0,ah=0,cats={};
    data.forEach(x=>{
      const m=Number(x.Monto)||0;
      if(x.Tipo==="Ingreso")ing+=m;
      else if(x.Tipo==="Gasto"){gas+=m;cats[x.Categoría]=(cats[x.Categoría]||0)+m;}
      if(String(x.Categoría||"").includes("Ahorro"))ah+=m;
    });
    const bal=ing-gas;
    const presupuestos=getBudgets();

    (goals||[]).forEach(g=>{
      const pct = g.valor>0 ? ((g.abonado||0)/g.valor*100) : 0;
      if(pct>=100){
        agregarNotificacion("meta_cumplida","🎉 ¡Meta alcanzada!",`Lograste tu meta "${g.nombre}" de ${money(g.valor)}.`,"meta_ok_"+g.nombre+"_"+contexto,contexto);
      } else if(pct>=90){
        agregarNotificacion("meta_cerca","🎯 Casi logras tu meta",`Vas en ${pct.toFixed(0)}% de tu meta "${g.nombre}" (${money(ah)} / ${money(g.valor)}).`,"meta_cerca_"+g.nombre+"_"+contexto,contexto);
      }
    });
  
    if(bal<0){
      agregarNotificacion("recomendacion","🔴 Gastos superan ingresos",`Estás ${money(Math.abs(bal))} en negativo este mes en ${contexto==="negocio"?"tu negocio":"tus finanzas personales"}.`,"reco_balneg_"+contexto+"_"+hoy,contexto);
    }
  
    if(ing>0){
      const tasaAhorro=(bal/ing)*100;
      if(tasaAhorro>0 && tasaAhorro<10){
        agregarNotificacion("recomendacion","🟠 Ahorro bajo",`Solo ahorras el ${tasaAhorro.toFixed(0)}% de tus ingresos. Intenta llegar al 10-20%.`,"reco_ahorro_"+contexto+"_"+hoy,contexto);
      }
    }
  
    Object.entries(presupuestos).forEach(([cat,lim])=>{
      const g=cats[cat]||0;
      if(g>=lim){
        agregarNotificacion("recomendacion","🚨 Presupuesto excedido",`Superaste el presupuesto de ${cat} por ${money(g-lim)}.`,"reco_presup_"+cat+"_"+contexto+"_"+hoy,contexto);
      } else if(g/lim>=0.8){
        agregarNotificacion("recomendacion","⚠️ Presupuesto casi al límite",`Ya usaste el ${((g/lim)*100).toFixed(0)}% del presupuesto de ${cat}.`,"reco_presup80_"+cat+"_"+contexto+"_"+hoy,contexto);
      }
    });
  
    if(contexto==="negocio" && ing>0){
      const margen=(bal/ing)*100;
      if(margen<15){
        agregarNotificacion("recomendacion","⚡ Margen bajo",`Tu margen de utilidad es del ${margen.toFixed(0)}%. Lo saludable es 25-40%.`,"reco_margen_"+hoy,contexto);
      }
    }
  }
